+    <div class="app">
+      <section class="panel">
+        <h1 class="title">Neon Serpent</h1>
+        <p class="subtitle">
+          Chase the glowing orbs, grow the serpent, and avoid your own trail. Use the arrow
+          keys to steer. Restart anytime if you get boxed in.
+        </p>
+        <div class="stats">
+          <div class="stat">
+            <span class="stat-label">Score</span>
+            <span class="stat-value" id="score">0</span>
