+            <span class="stat-label">Best</span>
+            <span class="stat-value" id="best">0</span>
+          </div>
+        </div>
+        <div class="controls">
+          <button id="restart">Restart Run</button>
+          <p class="hint">
+            Tip: Quick turns are faster than long runs. On mobile, use the directional
+            buttons below the board.
+          </p>
+          <div class="touch-controls">
+            <button class="up" data-dir="up">▲</button>
+            <button class="left" data-dir="left">◀</button>
+            <button class="right" data-dir="right">▶</button>
+            <button class="down" data-dir="down">▼</button>
+          </div>
+        </div>
+      </section>
+
+      <section class="game-card panel">
+        <canvas id="board" width="520" height="520" aria-label="Snake game board"></canvas>
+        <div class="overlay" id="overlay" aria-live="polite">
+          <h2>Game Over</h2>
+          <p>Press restart or hit Enter to go again.</p>
+        </div>
+      </section>
+    </div>
