+    <script>
+      const canvas = document.getElementById("board");
+      const ctx = canvas.getContext("2d");
+      const scoreEl = document.getElementById("score");
+      const bestEl = document.getElementById("best");
+      const overlay = document.getElementById("overlay");
+      const restartBtn = document.getElementById("restart");
+      const touchButtons = document.querySelectorAll(".touch-controls button");
+
+      const gridSize = 20;
+      const tiles = 20;
+      const tileSize = canvas.width / tiles;
+      const speedBase = 120;
+
+      let snake;
+      let direction;
+      let nextDirection;
+      let food;
+      let score;
+      let best;
+      let gameOver;
+      let lastTick;
+      let speed;
+
+      const storedBest = Number.parseInt(localStorage.getItem("neon-serpent-best"), 10);
+      best = Number.isNaN(storedBest) ? 0 : storedBest;
+      bestEl.textContent = best;
+
+      const directions = {
+        up: { x: 0, y: -1 },
+        down: { x: 0, y: 1 },
+        left: { x: -1, y: 0 },
+        right: { x: 1, y: 0 },
+      };
+
+      const opposite = {
+        up: "down",
+        down: "up",
+        left: "right",
+        right: "left",
+      };
+
+      function resetGame() {
+        snake = [
+          { x: 9, y: 10 },
+          { x: 8, y: 10 },
+          { x: 7, y: 10 },
+        ];
+        direction = "right";
+        nextDirection = "right";
+        score = 0;
+        speed = speedBase;
+        gameOver = false;
+        lastTick = performance.now();
+        spawnFood();
+        updateScore();
+        overlay.classList.remove("show");
+      }
+
+      function updateScore() {
+        scoreEl.textContent = score;
+        if (score > best) {
+          best = score;
+          bestEl.textContent = best;
+          localStorage.setItem("neon-serpent-best", String(best));
+        }
+      }
+
+      function spawnFood() {
+        let spot;
+        do {
+          spot = {
+            x: Math.floor(Math.random() * tiles),
+            y: Math.floor(Math.random() * tiles),
+          };
+        } while (snake.some((segment) => segment.x === spot.x && segment.y === spot.y));
+        food = spot;
+      }
+
+      function setDirection(newDir) {
+        if (gameOver) {
+          return;
+        }
+        if (opposite[newDir] === direction) {
+          return;
+        }
+        nextDirection = newDir;
+      }
+
+      function handleKey(event) {
+        const keyMap = {
+          ArrowUp: "up",
+          ArrowDown: "down",
+          ArrowLeft: "left",
+          ArrowRight: "right",
+        };
+        if (event.key === "Enter") {
+          resetGame();
+          return;
+        }
+        const dir = keyMap[event.key];
+        if (dir) {
+          event.preventDefault();
+          setDirection(dir);
+        }
+      }
+
+      function update() {
+        if (gameOver) {
+          return;
+        }
+        direction = nextDirection;
+        const head = snake[0];
+        const next = {
+          x: (head.x + directions[direction].x + tiles) % tiles,
+          y: (head.y + directions[direction].y + tiles) % tiles,
+        };
+
+        if (snake.some((segment) => segment.x === next.x && segment.y === next.y)) {
+          gameOver = true;
+          overlay.classList.add("show");
+          return;
+        }
+
+        snake.unshift(next);
+
+        if (next.x === food.x && next.y === food.y) {
+          score += 10;
+          speed = Math.max(60, speedBase - score);
+          spawnFood();
+          updateScore();
+        } else {
+          snake.pop();
+        }
+      }
+
+      function drawGrid() {
+        ctx.strokeStyle = "rgba(255, 255, 255, 0.05)";
+        ctx.lineWidth = 1;
+        for (let i = 0; i <= tiles; i += 1) {
+          ctx.beginPath();
+          ctx.moveTo(i * tileSize, 0);
+          ctx.lineTo(i * tileSize, canvas.height);
+          ctx.stroke();
+          ctx.beginPath();
+          ctx.moveTo(0, i * tileSize);
+          ctx.lineTo(canvas.width, i * tileSize);
+          ctx.stroke();
+        }
+      }
+
+      function drawFood() {
+        const pulse = 0.4 + Math.sin(performance.now() / 200) * 0.2;
+        const centerX = food.x * tileSize + tileSize / 2;
+        const centerY = food.y * tileSize + tileSize / 2;
+        const radius = tileSize * (0.26 + pulse * 0.15);
+        ctx.save();
+        const gradient = ctx.createRadialGradient(centerX, centerY, 2, centerX, centerY, radius * 2.2);
+        gradient.addColorStop(0, "rgba(246, 201, 69, 0.95)");
+        gradient.addColorStop(1, "rgba(246, 201, 69, 0.05)");
+        ctx.fillStyle = gradient;
+        ctx.beginPath();
+        ctx.arc(centerX, centerY, radius * 2.2, 0, Math.PI * 2);
+        ctx.fill();
+        ctx.fillStyle = "rgba(246, 201, 69, 1)";
+        ctx.beginPath();
+        ctx.arc(centerX, centerY, radius, 0, Math.PI * 2);
+        ctx.fill();
+        ctx.restore();
+      }
+
+      function drawSnake() {
+        snake.forEach((segment, index) => {
+          const x = segment.x * tileSize;
+          const y = segment.y * tileSize;
+          const radius = tileSize * 0.22;
+          const inset = tileSize * 0.12;
+          const gradient = ctx.createLinearGradient(x, y, x + tileSize, y + tileSize);
+          gradient.addColorStop(0, "rgba(111, 255, 168, 0.95)");
+          gradient.addColorStop(1, "rgba(26, 155, 99, 0.95)");
+          ctx.fillStyle = gradient;
+          ctx.beginPath();
+          ctx.roundRect(x + inset, y + inset, tileSize - inset * 2, tileSize - inset * 2, radius);
+          ctx.fill();
+
+          if (index === 0) {
+            ctx.fillStyle = "rgba(15, 19, 36, 0.8)";
+            ctx.beginPath();
+            ctx.roundRect(x + inset * 1.4, y + inset * 1.4, tileSize * 0.18, tileSize * 0.18, 4);
+            ctx.roundRect(x + tileSize * 0.55, y + inset * 1.4, tileSize * 0.18, tileSize * 0.18, 4);
+            ctx.fill();
+          }
+        });
+      }
+
+      function render() {
+        ctx.clearRect(0, 0, canvas.width, canvas.height);
+        drawGrid();
+        drawFood();
+        drawSnake();
+      }
+
+      function tick(time) {
+        const delta = time - lastTick;
+        if (delta > speed) {
+          update();
+          lastTick = time;
+        }
+        render();
+        requestAnimationFrame(tick);
+      }
+
+      restartBtn.addEventListener("click", resetGame);
+      window.addEventListener("keydown", handleKey, { passive: false });
+      touchButtons.forEach((button) => {
+        button.addEventListener("click", () => setDirection(button.dataset.dir));
+      });
+
+      resetGame();
+      requestAnimationFrame(tick);
+    </script>
+  </body>
+</html>
*** End Patch

